-- =========================================================
-- Script de datos de prueba - Sistema de Cobranza
-- Módulos: deudas, operadores, tickets, gestiones
-- Total: 50 deudas, 8 operadores, 50 tickets, ~90 gestiones
-- =========================================================

BEGIN;

-- ---------------------------------------------------------
-- OPERADORES
-- ---------------------------------------------------------

-- ---------------------------------------------------------
-- DEUDAS (50 registros, código de cliente formato CLI-YYYY-###)
-- ---------------------------------------------------------

-- ---------------------------------------------------------
-- TICKETS (uno por cada deuda, asignados a operadores 1-8)
-- ---------------------------------------------------------

-- ---------------------------------------------------------
-- GESTIONES (historial de acciones de cobranza por ticket)
-- ---------------------------------------------------------

COMMIT;

-- ---------------------------------------------------------
-- Sincronización de secuencias tras la carga manual de datos
-- ---------------------------------------------------------
SELECT setval('public.deudas_id_seq', (SELECT MAX(id) FROM public.deudas));
SELECT setval('public.operadores_id_seq', (SELECT MAX(id) FROM public.operadores));
SELECT setval('public.tickets_id_seq', (SELECT MAX(id) FROM public.tickets));
SELECT setval('public.gestiones_id_seq', (SELECT MAX(id) FROM public.gestiones));